import os
import tempfile
from pathlib import Path

class FilesystemSandbox:
    """
    Wraps a temporary directory. All agent file I/O must go through
    this class. Paths outside the sandbox raise PermissionError.
    """
    def __init__(self):
        self._tmpdir = tempfile.mkdtemp(prefix="agent_sandbox_")
        self.root = Path(self._tmpdir)

    def _safe_path(self, relative: str) -> Path:
        target = (self.root / relative).resolve()
        if not str(target).startswith(str(self.root)):
            raise PermissionError(
                f"Path escape attempt: '{relative}' resolves outside sandbox"
            )
        return target

    def write(self, relative: str, content: str) -> Path:
        path = self._safe_path(relative)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8")
        return path

    def read(self, relative: str) -> str:
        path = self._safe_path(relative)
        return path.read_text(encoding="utf-8")

    def list_files(self) -> list[str]:
        return [
            str(p.relative_to(self.root))
            for p in self.root.rglob("*")
            if p.is_file()
        ]

    def cleanup(self):
        import shutil
        shutil.rmtree(self._tmpdir, ignore_errors=True)

# Usage
sb = FilesystemSandbox()
try:
    sb.write("output/report.txt", "Agent results...")
    print(sb.read("output/report.txt"))
    print(sb.list_files())

    # Attempt to escape: resolved to /etc/passwd → PermissionError
    sb.write("../../etc/passwd", "malicious")
except PermissionError as e:
    print(f"Blocked: {e}")
finally:
    sb.cleanup()

import socket
from unittest.mock import patch

ALLOWED_HOSTS = {
    "api.anthropic.com",
    "api.openai.com",
}

_real_create_connection = socket.create_connection

def _guarded_create_connection(address, *args, **kwargs):
    host, port = address[0], address[1]
    if host not in ALLOWED_HOSTS:
        raise PermissionError(
            f"Network sandbox: connection to '{host}:{port}' is not allowed"
        )
    return _real_create_connection(address, *args, **kwargs)

class NetworkSandbox:
    """Context manager that restricts outbound TCP connections."""
    def __enter__(self):
        socket.create_connection = _guarded_create_connection
        return self

    def __exit__(self, *_):
        socket.create_connection = _real_create_connection

# Usage: all HTTP calls inside this block are filtered
