import anthropic
import json
import subprocess
import tempfile
from pathlib import Path

client = anthropic.Anthropic()

def execute_code_tool(code: str) -> str:
    """
    Sandboxed code execution tool for an agent.
    Runs code in a subprocess with filesystem isolation.
    Returns stdout or an error message.
    """
    with tempfile.TemporaryDirectory() as tmpdir:
        script = Path(tmpdir) / "run.py"
        script.write_text(code)
        try:
            result = subprocess.run(
                ["python3", str(script)],
                capture_output=True, text=True,
                timeout=10,
                cwd=tmpdir,
                env={"PATH": "/usr/bin:/bin", "HOME": tmpdir},
            )
            if result.returncode != 0:
                return f"Error (exit {result.returncode}):\n{result.stderr[:500]}"
            return result.stdout[:2000]
        except subprocess.TimeoutExpired:
            return "Error: code execution timed out (10s limit)"

tools = [
    {
        "name": "execute_python",
        "description": "Execute Python code and return its output. Code runs in an isolated sandbox with no network access.",
        "input_schema": {
            "type": "object",
            "properties": {
                "code": {"type": "string", "description": "Python code to execute"},
            },
            "required": ["code"],
        },
    }
]

def run_coding_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]
    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=tools,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            for block in resp.content:
                if hasattr(block, "text"):
                    return block.text
            return ""
        messages.append({"role": "assistant", "content": resp.content})
        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                output = execute_code_tool(block.input["code"])
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": output,
                })
        messages.append({"role": "user", "content": tool_results})

result = run_coding_agent("Write and run Python code that computes the first 10 Fibonacci numbers.")
print(result)
